import{_ as s,o as t,c as i,a0 as a}from"./chunks/framework.BjpW4enL.js";const g=JSON.parse('{"title":"ADR-0009: Synesthetic Topology — Nuance-Weighted Semantic Mesh","description":"","frontmatter":{},"headers":[],"relativePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/adr/0009-synesthetic-topology.md","filePath":"Z_Archive/wiki_legacy/archive/legacy_pre_federation/adr/0009-synesthetic-topology.md","lastUpdated":1782593311000}'),n={name:"Z_Archive/wiki_legacy/archive/legacy_pre_federation/adr/0009-synesthetic-topology.md"};function l(o,e,r,h,d,c){return t(),i("div",null,[...e[0]||(e[0]=[a(`<h1 id="adr-0009-synesthetic-topology-—-nuance-weighted-semantic-mesh" tabindex="-1">ADR-0009: Synesthetic Topology — Nuance-Weighted Semantic Mesh <a class="header-anchor" href="#adr-0009-synesthetic-topology-—-nuance-weighted-semantic-mesh" aria-label="Permalink to &quot;ADR-0009: Synesthetic Topology — Nuance-Weighted Semantic Mesh&quot;">​</a></h1><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>Accepted</p><h2 id="context-detailed-analysis" tabindex="-1">Context / Detailed Analysis <a class="header-anchor" href="#context-detailed-analysis" aria-label="Permalink to &quot;Context / Detailed Analysis&quot;">​</a></h2><h2 id="status-1" tabindex="-1">Status <a class="header-anchor" href="#status-1" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p><strong>ACCEPTED</strong> — Benchmark Study v1.0 (2026-03-25)</p><p>Evidence: See <code>workspace/outputs/ADR_009_STUDY_RESULTS.md</code></p><ul><li><strong>Architectural Shift</strong>: The original proposal focused on <em>filtering</em> stale paths. The benchmark study proved this is an anti-pattern for LLM context. ADR-009 succeeds as a <strong>continuous gradient modulation</strong>, not a binary filter. It subtly reshapes the probability mass distribution (score compression).</li><li><strong>Finding</strong>: β=0.3 produces healthy gradient compression (0% filtering). Minimum β-threshold for actual topological deletion is 2.33.</li><li><strong>Finding</strong>: Nightly batch precomputation viable (0.90 hours for 117,796 L0 abstractions).</li><li><strong>Open question resolved</strong>: L0 content used for drift (L1 deprecated — only 1,065 of 117,796).</li><li><strong>Recommended β</strong>: 0.3 for production (gradient reshaping mode).</li></ul><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>The T4 Semantic Mesh (topological layer) currently uses static <code>stress</code> values between nodes to drive PPR diffusion. This ADR proposes enriching the stress function with <strong>Nuance Vector dynamics</strong> computed from L1 abstraction embeddings: the semantic drift between connected abstractions becomes the primary signal for link strength. This transforms the topology from a static memory structure into a <strong>self-healing, self-pruning living geometry</strong> where relevance is determined by semantic coherence, not just connection count.</p><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>ADR-008 established that the differential between raw code (L0) and its semantic abstraction (L1) quantifies &quot;technical texture&quot; — the details the abstraction failed to capture. ADR-007 defined the topological layer (T4) as a causal graph of <code>hilbert_bridge</code> links between abstractions.</p><p><strong>The insight</strong>: if source and target abstractions of a link have drifted apart semantically (high ∆V between their L1 vectors), that link represents <strong>stale knowledge</strong> — a path that no longer reflects current codebase reality. Conversely, low ∆V means the link is <strong>topologically coherent</strong>.</p><p>This merges three ADRs into one unified principle: <strong>the topology is the semantic differential made graph</strong>.</p><h2 id="the-nuance-weighted-stress-function" tabindex="-1">The Nuance-Weighted Stress Function <a class="header-anchor" href="#the-nuance-weighted-stress-function" aria-label="Permalink to &quot;The Nuance-Weighted Stress Function&quot;">​</a></h2><h3 id="current-static" tabindex="-1">Current (Static) <a class="header-anchor" href="#current-static" aria-label="Permalink to &quot;Current (Static)&quot;">​</a></h3><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">stress(link) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> COALESCE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">l</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">stress</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- hardcoded or fixed</span></span></code></pre></div><h3 id="proposed-dynamic-nuance" tabindex="-1">Proposed (Dynamic Nuance) <a class="header-anchor" href="#proposed-dynamic-nuance" aria-label="Permalink to &quot;Proposed (Dynamic Nuance)&quot;">​</a></h3><div class="language-sql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">stress_weighted(s, t) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> σ(semantic_drift) × structural_stress</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">                       ────────────────────────────────</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">                       σ(∆V(V_L1[s], V_L1[t]))</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">where</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  semantic_drift </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> − cosine_similarity(V_L1[s], V_L1[t])</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  structural_stress </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> COALESCE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">l</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">stress</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- fallback to static</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  σ(x) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> − (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> /</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> +</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> x))  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- sigmoid normalization (0..1)</span></span></code></pre></div><p><strong>Effect</strong>: Links between semantically coherent abstractions are reinforced (lower effective stress). Links between drifted abstractions are penalized (higher effective stress).</p><h3 id="the-stress-function" tabindex="-1">The Stress Function <a class="header-anchor" href="#the-stress-function" aria-label="Permalink to &quot;The Stress Function&quot;">​</a></h3><p>Initial simulation used sigmoid σ(∆V) = 1 − (1/(1+∆V)) which proved <strong>too aggressive</strong> — killed all diffusion paths even for moderate drift. Corrected to mild linear penalty:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>nuance_weight(s, t) = (1 − drift[s,t] × β) × structural_stress</span></span>
<span class="line"><span>where drift[s,t] = 1 − cosine_similarity(V[s], V[t])</span></span>
<span class="line"><span>and β ∈ [0.1, 0.5] is a tunable sensitivity parameter (default: 0.3)</span></span></code></pre></div><table tabindex="0"><thead><tr><th>∆V (L1 divergence)</th><th>β=0.3</th><th>Effective weight</th></tr></thead><tbody><tr><td>0.0 (identical)</td><td>1.00</td><td>No penalty</td></tr><tr><td>0.1 (low drift)</td><td>0.97</td><td>Mild penalty</td></tr><tr><td>0.3 (minor drift)</td><td>0.91</td><td>Small penalty</td></tr><tr><td>0.7 (major drift)</td><td>0.79</td><td>Moderate penalty</td></tr><tr><td>1.0 (complete drift)</td><td>0.70</td><td>30% penalty</td></tr></tbody></table><h2 id="implications-for-ppr-diffusion" tabindex="-1">Implications for PPR Diffusion <a class="header-anchor" href="#implications-for-ppr-diffusion" aria-label="Permalink to &quot;Implications for PPR Diffusion&quot;">​</a></h2><p>Standard PPR:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>score[t] += (score[s] × α × w_structural) / degree[s]</span></span></code></pre></div><p>Nuance-Weighted PPR:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>score[t] += (score[s] × α × (1 − drift[s,t] × β) × w_structural) / degree[s]</span></span></code></pre></div><p><strong>Result</strong>: Diffusion naturally avoids paths where connected abstractions have drifted semantically, without deleting any node or link. The effect is selective — in simulation, 3 out of 78 reachable nodes were filtered at β=0.3 with drift 0.12-0.14.</p><p><strong>Result</strong>: Diffusion naturally avoids topological holes (regions of high semantic drift), without deleting any node or link. The knowledge that would have been accessed through a drifted path is simply not reached.</p><h2 id="semantic-drift-as-topological-hole" tabindex="-1">Semantic Drift as Topological Hole <a class="header-anchor" href="#semantic-drift-as-topological-hole" aria-label="Permalink to &quot;Semantic Drift as Topological Hole&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[A—B—C] original topology (all L1s aligned)</span></span>
<span class="line"><span>  ↓ code evolves: B and C change significantly but A stays the same</span></span>
<span class="line"><span>[A—B—C] now: A↔C has high ∆V (stale path), B↔C stays aligned</span></span>
<span class="line"><span>  ↓ PPR with Nuance-weighting</span></span>
<span class="line"><span>A can still reach B (low drift)</span></span>
<span class="line"><span>A CANNOT reach C through this path (high drift, link penalized)</span></span>
<span class="line"><span>  → C becomes TOPOLOGICALLY INACCESSIBLE without deletion</span></span></code></pre></div><h2 id="what-is-not-deleted" tabindex="-1">What is NOT Deleted <a class="header-anchor" href="#what-is-not-deleted" aria-label="Permalink to &quot;What is NOT Deleted&quot;">​</a></h2><ul><li>The <code>links</code> table is <strong>never modified</strong> — only the computed weight changes per query</li><li>Abstractions are <strong>never deleted</strong> — they simply become unreachable topologically</li><li>The Qdrant vectors are <strong>never recomputed</strong> unless explicitly re-ingested</li><li>Historical state is <strong>preserved</strong> — <code>evolved_from</code> and <code>supersedes</code> still trace lineage</li></ul><h2 id="simulation-plan" tabindex="-1">Simulation Plan <a class="header-anchor" href="#simulation-plan" aria-label="Permalink to &quot;Simulation Plan&quot;">​</a></h2><ol><li>Sample N links from <code>links</code> table</li><li>For each (source, target) pair: <ul><li>Fetch L1 content from both abstractions</li><li>Embed both with Ollama (nomic-embed-text)</li><li>Compute <code>σ(1 − cosine_similarity(V1, V2))</code></li></ul></li><li>Run PPR twice on the same seed: <ul><li>Run A: using static <code>COALESCE(stress, 1.0)</code></li><li>Run B: using <code>σ(∆V) × COALESCE(stress, 1.0)</code></li></ul></li><li>Compare: which nodes are reachable in A but NOT in B?</li></ol><h2 id="open-questions" tabindex="-1">Open Questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open Questions&quot;">​</a></h2><ul><li>[ ] Is L1 content sufficient for drift detection, or should we use L0 (raw code)?</li><li>[ ] Should the sigmoid normalization σ be tunable per query (as a parameter)?</li><li>[ ] Does the computational cost of embedding all link endpoints per query make this prohibitive? <ul><li>Mitigation: compute Nuance-weighted stress <strong>periodically</strong> (offline), not per query</li></ul></li><li>[ ] Can we combine with the decay simulation (ADR-009-SENSORIA) to create a two-layer filter: topological (Nuance) + temporal (decay)?</li></ul><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li>ADR-007: Causalidade Topológica (T4 layer)</li><li>ADR-008: Synesthesia and the Nuance Vector</li><li>ACT-R Base-Level Activation (for decay integration)</li></ul>`,41)])])}const u=s(n,[["render",l]]);export{g as __pageData,u as default};
